mapper.sql:
WHERE trade_date BETWEEN #{start} AND #{end}

    AND change_type = #{changeType}


    AND ABS(total_price)  >=  #{totalPrice}

mapper.select:
SELECT
track_time      AS trackTime,
current_price   AS currentPrice
FROM stock_price_tracking
WHERE stock_code = #{code}

    AND track_time  >=  #{startTime}


    AND track_time  <  #{endTime}

ORDER BY track_time

SELECT trade_date AS tradeDate, stock_code AS stockCode, stock_name AS stockName, change_type AS changeType, ABS(total_price) AS totalPrice, price AS price, changer_name AS changerName, changer_position AS changerPosition FROM daily_stock_change WHERE stock_code = #{code}
AND trade_date >= #{start}
AND trade_date <= #{end}
ORDER BY trade_date
